parameters.jsCode:
let text = $input.item.json.text || "";

// Remove markdown JSON codeblocks if present
text = text.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsedData = {};
try {
  parsedData = JSON.parse(text);
} catch (e) {
  parsedData = {
    "Job ID": $input.item.json.job_id || ("ERROR-" + Math.floor(Math.random()*1000)),
    "Job Title": "Error parsing output",
    "Company": "Error",
    "URL": "",
    "Employment Type": "N/A",
    "Is Remote": "N/A",
    "Location": "N/A",
    "Salary": "N/A",
    "Relevance Score": 0,
    "Skill Match Score": 0,
    "Joining Timeline": "N/A",
    "Summary": "Failed to parse Gemini output: " + e.message,
    "Status": "Not Applied",
    "Job Description": "N/A",
    "Language": [],
    "Apply Options": [],
    "Posted On": ""
  };
}

// Map Job Id back to Job ID if Notion requires exact casing
if (parsedData["Job Id"] && !parsedData["Job ID"]) {
  parsedData["Job ID"] = parsedData["Job Id"];
}

// Helper to convert to array
function toArray(val) {
  if (Array.isArray(val)) return val.map(v => typeof v === 'string' ? v : JSON.stringify(v));
  if (typeof val === 'string') {
    if (val.toUpperCase() === "N/A" || val.trim() === "") return [];
    return val.split(',').map(s => s.trim()).filter(s => s);
  }
  return [];
}

// Clean up Multiselect fields
parsedData["Apply Options"] = toArray(parsedData["Apply Options"]);
parsedData["Language"] = toArray(parsedData["Language"]);

if (parsedData["Apply Options"].length === 1 && parsedData["Apply Options"][0].toUpperCase() === "N/A") {
  parsedData["Apply Options"] = [];
}
if (parsedData["Language"].length === 1 && parsedData["Language"][0].toUpperCase() === "N/A") {
  parsedData["Language"] = [];
}

// Clean up Select fields to strictly match Notion options
let isRemote = parsedData["Is Remote"];
if (typeof isRemote === 'string') {
  let irUpper = isRemote.toUpperCase();
  if (irUpper.includes("YES") || irUpper.includes("TRUE")) parsedData["Is Remote"] = "Yes";
  else if (irUpper.includes("HYBRID")) parsedData["Is Remote"] = "Hybrid";
  else if (irUpper.includes("NO") || irUpper.includes("FALSE")) parsedData["Is Remote"] = "No";
  else parsedData["Is Remote"] = "N/A";
} else {
  parsedData["Is Remote"] = "N/A";
}

let empType = parsedData["Employment Type"];
if (typeof empType === 'string') {
  let etUpper = empType.toUpperCase();
  if (etUpper.includes("FULL") && etUpper.includes("TIME")) parsedData["Employment Type"] = "Full-Time";
  else if (etUpper.includes("PART") && etUpper.includes("TIME")) parsedData["Employment Type"] = "Part-Time";
  else parsedData["Employment Type"] = "N/A";
} else {
  parsedData["Employment Type"] = "N/A";
}

parsedData["Status"] = "Not Applied";

return parsedData;
